+import { describe, it, expect, beforeEach } from 'vitest';
+import {
+  WebhookNotificationAdapter,
+  InMemoryWebhookTransport,
+} from '../../src/adapters/webhook.adapter.js';
+import type {
+  WebhookTransport,
+  WebhookPayload,
+} from '../../src/adapters/webhook.adapter.js';
+import type { NotificationPayload } from '../../src/models/notification.js';
+
+function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
+  return {
+    recipient: 'user-1',
+    subject: 'Order Confirmation: order-1',
+    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
+    channel: 'webhook',
+    notificationType: 'order_confirmation',
+    metadata: { orderId: 'order-1', userId: 'user-1' },
+    ...overrides,
+  };
+}
+
+describe('WebhookNotificationAdapter', () => {
+  let adapter: WebhookNotificationAdapter;
+  let transport: InMemoryWebhookTransport;
+
+  beforeEach(() => {
+    transport = new InMemoryWebhookTransport();
+    adapter = new WebhookNotificationAdapter(
+      { url: 'https://hooks.example.com/notify' },
+      transport,
+    );
+  });
+
+  // -----------------------------------------------------------------------
+  // Basic send
+  // -----------------------------------------------------------------------
+
+  it('should deliver a webhook successfully', async () => {
+    const result = await adapter.send(makePayload());
+
+    expect(result.success).toBe(true);
+    const sent = adapter.getSentWebhooks();
+    expect(sent).toHaveLength(1);
+    expect(sent[0]?.url).toBe('https://hooks.example.com/notify');
+    expect(sent[0]?.payload.event).toBe('order_confirmation');
+  });
+
+  it('should format payload as JSON with correct fields', async () => {
+    await adapter.send(makePayload());
+
+    const sent = adapter.getSentWebhooks();
+    const payload = sent[0]?.payload;
+    expect(payload?.event).toBe('order_confirmation');
+    expect(payload?.recipient).toBe('user-1');
+    expect(payload?.subject).toBe('Order Confirmation: order-1');
+    expect(payload?.body).toContain('Widget x2');
+    expect(payload?.metadata).toEqual({ orderId: 'order-1', userId: 'user-1' });
+    expect(payload?.timestamp).toBeDefined();
+  });
+
+  it('should include ISO timestamp in payload', async () => {
+    await adapter.send(makePayload());
+
+    const sent = adapter.getSentWebhooks();
+    const timestamp = sent[0]?.payload.timestamp;
+    // Verify it's a valid ISO date string
+    expect(new Date(timestamp!).toISOString()).toBe(timestamp);
+  });
+
+  // -----------------------------------------------------------------------
+  // URL validation
+  // -----------------------------------------------------------------------
+
+  it('should fail when URL is not configured', async () => {
+    adapter = new WebhookNotificationAdapter({ url: '' }, transport);
+    const result = await adapter.send(makePayload());
+
+    expect(result.success).toBe(false);
+    expect(result.error).toBe('Webhook URL is not configured');
+    expect(adapter.getSentWebhooks()).toHaveLength(0);
+  });
+
+  it('should fail when URL is undefined (default)', async () => {
+    adapter = new WebhookNotificationAdapter(undefined, transport);
+    const result = await adapter.send(makePayload());
+
+    expect(result.success).toBe(false);
+    expect(result.error).toBe('Webhook URL is not configured');
+  });
+
+  // -----------------------------------------------------------------------
+  // Notification types
+  // -----------------------------------------------------------------------
+
+  it('should format order_status_update events', async () => {
+    await adapter.send(
+      makePayload({
+        notificationType: 'order_status_update',
+        body: 'Status changed from pending to confirmed.',
+      }),
+    );
+
+    const sent = adapter.getSentWebhooks();
+    expect(sent[0]?.payload.event).toBe('order_status_update');
+    expect(sent[0]?.payload.body).toContain('pending to confirmed');
+  });
+
+  it('should format user_welcome events', async () => {
+    await adapter.send(
+      makePayload({
+        notificationType: 'user_welcome',
+        subject: 'Welcome!',
+        body: 'Welcome aboard, Alice!',
+        metadata: undefined,
+      }),
+    );
+
+    const sent = adapter.getSentWebhooks();
+    expect(sent[0]?.payload.event).toBe('user_welcome');
+    expect(sent[0]?.payload.metadata).toBeUndefined();
+  });
+
+  it('should format user_updated events', async () => {
+    await adapter.send(
+      makePayload({
+        notificationType: 'user_updated',
+        subject: 'Account Updated',
+        body: 'Your email has been changed.',
+      }),
+    );
+
+    const sent = adapter.getSentWebhooks();
+    expect(sent[0]?.payload.event).toBe('user_updated');
+  });
+
+  // -----------------------------------------------------------------------
+  // Retry logic
+  // -----------------------------------------------------------------------
+
+  it('should retry on transport failure', async () => {
+    let attempts = 0;
+    const failingTransport: WebhookTransport = {
+      async post() {
+        attempts++;
+        if (attempts < 3) {
+          throw new Error('Connection timeout');
+        }
+      },
+    };
+
+    adapter = new WebhookNotificationAdapter(
+      { url: 'https://hooks.example.com/notify', maxRetries: 2 },
+      failingTransport,
+    );
+    const result = await adapter.send(makePayload());
+
+    expect(result.success).toBe(true);
+    expect(attempts).toBe(3); // 1 initial + 2 retries
+  });
+
+  it('should return failure after exhausting retries', async () => {
+    const failingTransport: WebhookTransport = {
+      async post() {
+        throw new Error('Permanent failure');
+      },
+    };
+
+    adapter = new WebhookNotificationAdapter(
+      { url: 'https://hooks.example.com/notify', maxRetries: 1 },
+      failingTransport,
+    );
+    const result = await adapter.send(makePayload());
+
+    expect(result.success).toBe(false);
+    expect(result.error).toBe('Permanent failure');
+  });
+
+  it('should succeed on first attempt when no errors', async () => {
+    let attempts = 0;
+    const countingTransport: WebhookTransport = {
+      async post() {
+        attempts++;
+      },
+    };
+
+    adapter = new WebhookNotificationAdapter(
+      { url: 'https://hooks.example.com/notify', maxRetries: 3 },
+      countingTransport,
+    );
+    await adapter.send(makePayload());
+
+    expect(attempts).toBe(1);
+  });
+
+  // -----------------------------------------------------------------------
+  // Configuration
+  // -----------------------------------------------------------------------
+
+  it('should expose config via getConfig', () => {
+    adapter = new WebhookNotificationAdapter({
+      url: 'https://hooks.example.com/notify',
+      secret: 'my-secret',
+      maxRetries: 5,
+    });
+
+    const config = adapter.getConfig();
+    expect(config.url).toBe('https://hooks.example.com/notify');
+    expect(config.secret).toBe('my-secret');
+    expect(config.maxRetries).toBe(5);
+  });
+
+  it('should pass secret to transport', async () => {
+    let receivedSecret: string | undefined;
+    const spyTransport: WebhookTransport = {
+      async post(_url: string, _payload: WebhookPayload, secret?: string) {
+        receivedSecret = secret;
+      },
+    };
+
+    adapter = new WebhookNotificationAdapter(
+      { url: 'https://hooks.example.com/notify', secret: 'my-secret' },
+      spyTransport,
+    );
+    await adapter.send(makePayload());
+
+    expect(receivedSecret).toBe('my-secret');
+  });
+
+  // -----------------------------------------------------------------------
+  // Clearing
+  // -----------------------------------------------------------------------
+
+  it('should clear sent webhooks', async () => {
+    await adapter.send(makePayload());
+    expect(adapter.getSentWebhooks()).toHaveLength(1);
+
+    adapter.clearSentWebhooks();
+    expect(adapter.getSentWebhooks()).toHaveLength(0);
+  });
+
+  // -----------------------------------------------------------------------
+  // Channel
+  // -----------------------------------------------------------------------
+
+  it('should report webhook channel', () => {
+    expect(adapter.channel).toBe('webhook');
+  });
+
+  // -----------------------------------------------------------------------
+  // formatPayload
+  // -----------------------------------------------------------------------
+
+  it('should expose formatPayload for direct use', () => {
+    const formatted = adapter.formatPayload(makePayload());
+
+    expect(formatted.event).toBe('order_confirmation');
+    expect(formatted.recipient).toBe('user-1');
+    expect(formatted.subject).toBe('Order Confirmation: order-1');
+    expect(formatted.timestamp).toBeDefined();
+  });
+});
+
+describe('InMemoryWebhookTransport', () => {
+  it('should store and retrieve delivered webhooks', async () => {
+    const transport = new InMemoryWebhookTransport();
+
+    await transport.post('https://example.com/hook', {
+      event: 'order_confirmation',
+      recipient: 'user-1',
+      subject: 'Test',
+      body: 'Hello',
+      timestamp: new Date().toISOString(),
+    });
+
+    const webhooks = transport.getDeliveredWebhooks();
+    expect(webhooks).toHaveLength(1);
+    expect(webhooks[0]?.url).toBe('https://example.com/hook');
+  });
+
+  it('should clear delivered webhooks', async () => {
+    const transport = new InMemoryWebhookTransport();
+
+    await transport.post('https://example.com/hook', {
+      event: 'order_confirmation',
+      recipient: 'user-1',
+      subject: 'Test',
+      body: 'Hello',
+      timestamp: new Date().toISOString(),
+    });
+
+    transport.clear();
+    expect(transport.getDeliveredWebhooks()).toHaveLength(0);
+  });
+});

