/**
 * Webhook notification adapter.
 *
 * Implements NotificationAdapter for the 'webhook' channel.
 * Formats notification payloads as JSON and POSTs them to a configured URL.
 *
 * In production the transport would use fetch/axios to make real HTTP calls.
 * The default transport stores requests in memory for testing.
 */

import type { NotificationAdapter, DeliveryResult } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationChannel,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------

export interface WebhookConfig {
  /** The URL to POST webhook payloads to. */
  url: string;
  /** Optional secret for signing payloads (e.g. HMAC). */
  secret?: string;
  /** Maximum delivery attempts before giving up. */
  maxRetries: number;
}

const DEFAULT_WEBHOOK_CONFIG: WebhookConfig = {
  url: '',
  maxRetries: 2,
};

// ---------------------------------------------------------------------------
// Webhook payload type
// ---------------------------------------------------------------------------

export interface WebhookPayload {
  event: string;
  recipient: string;
  subject: string;
  body: string;
  metadata?: Record<string, string>;
  timestamp: string;
}

// ---------------------------------------------------------------------------
// Transport abstraction
// ---------------------------------------------------------------------------

/**
 * Pluggable transport that actually delivers the webhook POST.
 * The default implementation stores payloads in memory (for testing).
 * In production, swap this for an HTTP transport.
 */
export interface WebhookTransport {
  post(url: string, payload: WebhookPayload, secret?: string): Promise<void>;
}

/**
 * Sent webhook record — includes the URL, payload, and timestamp.
 */
export interface SentWebhook {
  url: string;
  payload: WebhookPayload;
  sentAt: Date;
}

/**
 * In-memory transport — stores posted webhooks for inspection in tests.
 */
export class InMemoryWebhookTransport implements WebhookTransport {
  private deliveredWebhooks: SentWebhook[] = [];

  async post(url: string, payload: WebhookPayload): Promise<void> {
    this.deliveredWebhooks.push({
      url,
      payload,
      sentAt: new Date(),
    });
  }

  getDeliveredWebhooks(): SentWebhook[] {
    return [...this.deliveredWebhooks];
  }

  clear(): void {
    this.deliveredWebhooks = [];
  }
}

// ---------------------------------------------------------------------------
// Adapter
// ---------------------------------------------------------------------------

export class WebhookNotificationAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'webhook';

  private logger = new Logger('WebhookAdapter');
  private config: WebhookConfig;
  private transport: WebhookTransport;

  constructor(config?: Partial<WebhookConfig>, transport?: WebhookTransport) {
    this.config = { ...DEFAULT_WEBHOOK_CONFIG, ...config };
    this.transport = transport ?? new InMemoryWebhookTransport();
  }

  /**
   * Format the notification payload as JSON and POST it to the configured URL.
   *
   * Per the NotificationAdapter contract this method never throws.
   */
  async send(payload: NotificationPayload): Promise<DeliveryResult> {
    try {
      // 1. Validate URL
      if (!this.config.url) {
        const error = 'Webhook URL is not configured';
        this.logger.error(error);
        return { success: false, error };
      }

      // 2. Format payload
      const webhookPayload = this.formatPayload(payload);

      // 3. Attempt delivery with retries
      let lastError: string | undefined;
      for (let attempt = 0; attempt <= this.config.maxRetries; attempt++) {
        try {
          await this.transport.post(this.config.url, webhookPayload, this.config.secret);
          this.logger.info(
            `Webhook delivered to ${this.config.url}: ${payload.notificationType}`,
          );
          return { success: true };
        } catch (err: unknown) {
          lastError = err instanceof Error ? err.message : 'Transport error';
          this.logger.warn(
            `Delivery attempt ${attempt + 1} failed for ${this.config.url}: ${lastError}`,
          );
        }
      }

      this.logger.error(
        `All delivery attempts exhausted for ${this.config.url}: ${lastError}`,
      );
      return { success: false, error: lastError };
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : 'Unknown webhook error';
      this.logger.error(`Unexpected error posting to ${this.config.url}: ${message}`);
      return { success: false, error: message };
    }
  }

  /**
   * Format a NotificationPayload into a webhook JSON payload.
   */
  formatPayload(payload: NotificationPayload): WebhookPayload {
    return {
      event: payload.notificationType,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      metadata: payload.metadata,
      timestamp: new Date().toISOString(),
    };
  }

  // -----------------------------------------------------------------------
  // Convenience accessors (primarily for testing)
  // -----------------------------------------------------------------------

  /**
   * Get all webhooks sent through this adapter.
   * Only works when using InMemoryWebhookTransport.
   */
  getSentWebhooks(): SentWebhook[] {
    if (this.transport instanceof InMemoryWebhookTransport) {
      return this.transport.getDeliveredWebhooks();
    }
    return [];
  }

  /**
   * Clear sent webhook history.
   * Only works when using InMemoryWebhookTransport.
   */
  clearSentWebhooks(): void {
    if (this.transport instanceof InMemoryWebhookTransport) {
      this.transport.clear();
    }
  }

  /**
   * Get the current configuration (useful for testing).
   */
  getConfig(): Readonly<WebhookConfig> {
    return { ...this.config };
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
